using Contoso.Orders;

namespace Contoso.Orders.Tests;

[TestClass]
public sealed class OrderServiceTests
{
    private readonly OrderService _service;

    public OrderServiceTests()
    {
        _service = new OrderService();
    }

    private static List<OrderItem> CreateItems(params (string name, decimal price, int qty)[] items) =>
        items.Select(i => new OrderItem { ProductName = i.name, Price = i.price, Quantity = i.qty }).ToList();

    #region CreateOrder - Success

    [TestMethod]
    public void CreateOrder_WithValidItems_ReturnsOrderWithCorrectCustomerId()
    {
        // Arrange
        var items = CreateItems(("Widget", 10m, 2));

        // Act
        var order = _service.CreateOrder("cust-1", items);

        // Assert
        Assert.AreEqual("cust-1", order.CustomerId);
    }

    [TestMethod]
    public void CreateOrder_WithSingleItem_CalculatesTotalCorrectly()
    {
        // Arrange
        var items = CreateItems(("Widget", 25.50m, 3));

        // Act
        var order = _service.CreateOrder("cust-1", items);

        // Assert
        Assert.AreEqual(76.50m, order.Total);
    }

    [TestMethod]
    public void CreateOrder_WithMultipleItems_SumsTotalAcrossAllItems()
    {
        // Arrange
        var items = CreateItems(("Widget", 10m, 2), ("Gadget", 5m, 4));

        // Act
        var order = _service.CreateOrder("cust-1", items);

        // Assert
        Assert.AreEqual(40m, order.Total); // (10*2) + (5*4)
    }

    [TestMethod]
    public void CreateOrder_AssignsNonEmptyId()
    {
        // Arrange
        var items = CreateItems(("Widget", 10m, 1));

        // Act
        var order = _service.CreateOrder("cust-1", items);

        // Assert
        Assert.IsNotNull(order.Id);
        Assert.IsNotEmpty(order.Id);
    }

    [TestMethod]
    public void CreateOrder_SetsCreatedAtToRecentTime()
    {
        // Arrange
        var items = CreateItems(("Widget", 10m, 1));
        var before = DateTime.UtcNow;

        // Act
        var order = _service.CreateOrder("cust-1", items);

        // Assert
        var after = DateTime.UtcNow;
        Assert.IsInRange(order.CreatedAt, before, after);
    }

    [TestMethod]
    public void CreateOrder_StoresItemsOnOrder()
    {
        // Arrange
        var items = CreateItems(("Widget", 10m, 1), ("Gadget", 5m, 2));

        // Act
        var order = _service.CreateOrder("cust-1", items);

        // Assert
        Assert.HasCount(2, order.Items);
    }

    #endregion

    #region CreateOrder - Validation

    [TestMethod]
    public void CreateOrder_WithNullCustomerId_ThrowsArgumentNullException()
    {
        var items = CreateItems(("Widget", 10m, 1));

        var ex = Assert.ThrowsExactly<ArgumentNullException>(
            () => _service.CreateOrder(null!, items));
        Assert.AreEqual("customerId", ex.ParamName);
    }

    [TestMethod]
    public void CreateOrder_WithNullItems_ThrowsArgumentNullException()
    {
        var ex = Assert.ThrowsExactly<ArgumentNullException>(
            () => _service.CreateOrder("cust-1", null!));
        Assert.AreEqual("items", ex.ParamName);
    }

    [TestMethod]
    public void CreateOrder_WithEmptyItems_ThrowsInvalidOperationException()
    {
        Assert.ThrowsExactly<InvalidOperationException>(
            () => _service.CreateOrder("cust-1", []));
    }

    #endregion

    #region GetOrder

    [TestMethod]
    public void GetOrder_ExistingOrder_ReturnsMatchingOrder()
    {
        // Arrange
        var items = CreateItems(("Widget", 10m, 1));
        var created = _service.CreateOrder("cust-1", items);

        // Act
        var retrieved = _service.GetOrder(created.Id);

        // Assert
        Assert.IsNotNull(retrieved);
        Assert.AreEqual(created.Id, retrieved.Id);
    }

    [TestMethod]
    public void GetOrder_NonExistentId_ReturnsNull()
    {
        var result = _service.GetOrder("does-not-exist");

        Assert.IsNull(result);
    }

    #endregion

    #region GetOrdersByCustomer

    [TestMethod]
    public void GetOrdersByCustomer_WithOrders_ReturnsOnlyThatCustomersOrders()
    {
        // Arrange
        var items = CreateItems(("Widget", 10m, 1));
        _service.CreateOrder("cust-1", items);
        _service.CreateOrder("cust-1", items);
        _service.CreateOrder("cust-2", items);

        // Act
        var orders = _service.GetOrdersByCustomer("cust-1");

        // Assert
        Assert.HasCount(2, orders);
    }

    [TestMethod]
    public void GetOrdersByCustomer_NoOrders_ReturnsEmptyList()
    {
        var orders = _service.GetOrdersByCustomer("unknown");

        Assert.IsEmpty(orders);
    }

    #endregion
}

using Contoso.Pricing;

namespace Contoso.Pricing.Tests;

[TestClass]
public sealed class PriceCalculatorTests
{
    private readonly PriceCalculator _calculator;

    public PriceCalculatorTests()
    {
        _calculator = new PriceCalculator();
    }

    #region CalculateTotal

    [TestMethod]
    [DataRow(10.00, 2, 0.10, 22.00, DisplayName = "10% tax")]
    [DataRow(5.00, 3, 0.0, 15.00, DisplayName = "No tax")]
    [DataRow(100.00, 1, 0.25, 125.00, DisplayName = "25% tax")]
    public void CalculateTotal_WithValidInputs_ReturnsExpectedTotal(
        double unitPrice, int quantity, double taxRate, double expected)
    {
        var result = _calculator.CalculateTotal((decimal)unitPrice, quantity, (decimal)taxRate);

        Assert.AreEqual((decimal)expected, result);
    }

    [TestMethod]
    public void CalculateTotal_ZeroQuantity_ReturnsZero()
    {
        var result = _calculator.CalculateTotal(50m, 0, 0.10m);

        Assert.AreEqual(0m, result);
    }

    [TestMethod]
    public void CalculateTotal_NegativeQuantity_ThrowsArgumentOutOfRangeException()
    {
        var ex = Assert.ThrowsExactly<ArgumentOutOfRangeException>(
            () => _calculator.CalculateTotal(10m, -1, 0.10m));
        Assert.AreEqual("quantity", ex.ParamName);
    }

    [TestMethod]
    public void CalculateTotal_NegativeUnitPrice_ThrowsArgumentOutOfRangeException()
    {
        var ex = Assert.ThrowsExactly<ArgumentOutOfRangeException>(
            () => _calculator.CalculateTotal(-5m, 1, 0.10m));
        Assert.AreEqual("unitPrice", ex.ParamName);
    }

    [TestMethod]
    [DataRow(-0.01, DisplayName = "Below zero")]
    [DataRow(1.01, DisplayName = "Above one")]
    public void CalculateTotal_InvalidTaxRate_ThrowsArgumentOutOfRangeException(double taxRate)
    {
        var ex = Assert.ThrowsExactly<ArgumentOutOfRangeException>(
            () => _calculator.CalculateTotal(10m, 1, (decimal)taxRate));
        Assert.AreEqual("taxRate", ex.ParamName);
    }

    #endregion

    #region ApplyDiscount

    [TestMethod]
    [DataRow(100.00, 10.0, 90.00, DisplayName = "10% off")]
    [DataRow(200.00, 50.0, 100.00, DisplayName = "50% off")]
    [DataRow(80.00, 0.0, 80.00, DisplayName = "No discount")]
    [DataRow(80.00, 100.0, 0.00, DisplayName = "100% off")]
    public void ApplyDiscount_ValidInputs_ReturnsExpectedPrice(
        double price, double discount, double expected)
    {
        var result = _calculator.ApplyDiscount((decimal)price, (decimal)discount);

        Assert.AreEqual((decimal)expected, result);
    }

    [TestMethod]
    [DataRow(-1.0, DisplayName = "Negative discount")]
    [DataRow(101.0, DisplayName = "Over 100% discount")]
    public void ApplyDiscount_InvalidPercent_ThrowsArgumentOutOfRangeException(double discount)
    {
        Assert.ThrowsExactly<ArgumentOutOfRangeException>(
            () => _calculator.ApplyDiscount(100m, (decimal)discount));
    }

    #endregion

    #region FormatPrice

    [TestMethod]
    public void FormatPrice_DefaultSymbol_FormatsWithDollarSign()
    {
        var result = _calculator.FormatPrice(19.99m);

        Assert.AreEqual("$19.99", result);
    }

    [TestMethod]
    public void FormatPrice_CustomSymbol_UsesProvidedSymbol()
    {
        var result = _calculator.FormatPrice(19.99m, "€");

        Assert.StartsWith("€", result);
    }

    [TestMethod]
    public void FormatPrice_RoundsFractionalCents()
    {
        var result = _calculator.FormatPrice(9.999m);

        Assert.AreEqual("$10.00", result);
    }

    #endregion
}

