using Contoso.Pricing;

namespace Contoso.Pricing.Tests;

[TestClass]
public sealed class PriceCalculatorTests
{
    private readonly PriceCalculator _calculator;

    public PriceCalculatorTests()
    {
        _calculator = new PriceCalculator();
    }

    #region CalculateTotal

    [TestMethod]
    [DataRow(10.00, 2, 0.10, 22.00, DisplayName = "10% tax")]
    [DataRow(5.00, 3, 0.0, 15.00, DisplayName = "No tax")]
    [DataRow(100.00, 1, 0.25, 125.00, DisplayName = "25% tax")]
    public void CalculateTotal_WithValidInputs_ReturnsExpectedTotal(
        double unitPrice, int quantity, double taxRate, double expected)
    {
        var result = _calculator.CalculateTotal((decimal)unitPrice, quantity, (decimal)taxRate);

        Assert.AreEqual((decimal)expected, result);
    }

    [TestMethod]
    public void CalculateTotal_ZeroQuantity_ReturnsZero()
    {
        var result = _calculator.CalculateTotal(50m, 0, 0.10m);

        Assert.AreEqual(0m, result);
    }

    [TestMethod]
    public void CalculateTotal_NegativeQuantity_ThrowsArgumentOutOfRangeException()
    {
        var ex = Assert.ThrowsExactly<ArgumentOutOfRangeException>(
            () => _calculator.CalculateTotal(10m, -1, 0.10m));
        Assert.AreEqual("quantity", ex.ParamName);
    }

    [TestMethod]
    public void CalculateTotal_NegativeUnitPrice_ThrowsArgumentOutOfRangeException()
    {
        var ex = Assert.ThrowsExactly<ArgumentOutOfRangeException>(
            () => _calculator.CalculateTotal(-5m, 1, 0.10m));
        Assert.AreEqual("unitPrice", ex.ParamName);
    }

    [TestMethod]
    [DataRow(-0.01, DisplayName = "Below zero")]
    [DataRow(1.01, DisplayName = "Above one")]
    public void CalculateTotal_InvalidTaxRate_ThrowsArgumentOutOfRangeException(double taxRate)
    {
        var ex = Assert.ThrowsExactly<ArgumentOutOfRangeException>(
            () => _calculator.CalculateTotal(10m, 1, (decimal)taxRate));
        Assert.AreEqual("taxRate", ex.ParamName);
    }

    #endregion

    #region ApplyDiscount

    [TestMethod]
    [DataRow(100.00, 10.0, 90.00, DisplayName = "10% off")]
    [DataRow(200.00, 50.0, 100.00, DisplayName = "50% off")]
    [DataRow(80.00, 0.0, 80.00, DisplayName = "No discount")]
    [DataRow(80.00, 100.0, 0.00, DisplayName = "100% off")]
    public void ApplyDiscount_ValidInputs_ReturnsExpectedPrice(
        double price, double discount, double expected)
    {
        var result = _calculator.ApplyDiscount((decimal)price, (decimal)discount);

        Assert.AreEqual((decimal)expected, result);
    }

    [TestMethod]
    [DataRow(-1.0, DisplayName = "Negative discount")]
    [DataRow(101.0, DisplayName = "Over 100% discount")]
    public void ApplyDiscount_InvalidPercent_ThrowsArgumentOutOfRangeException(double discount)
    {
        Assert.ThrowsExactly<ArgumentOutOfRangeException>(
            () => _calculator.ApplyDiscount(100m, (decimal)discount));
    }

    #endregion

    #region FormatPrice

    [TestMethod]
    public void FormatPrice_DefaultSymbol_FormatsWithDollarSign()
    {
        var result = _calculator.FormatPrice(19.99m);

        Assert.AreEqual("$19.99", result);
    }

    [TestMethod]
    public void FormatPrice_CustomSymbol_UsesProvidedSymbol()
    {
        var result = _calculator.FormatPrice(19.99m, "€");

        Assert.StartsWith("€", result);
    }

    [TestMethod]
    public void FormatPrice_RoundsFractionalCents()
    {
        var result = _calculator.FormatPrice(9.999m);

        Assert.AreEqual("$10.00", result);
    }

    #endregion
}

